package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;
import java.util.*;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

public class CSVRecordTest {

    private CSVRecord csvRecord;
    private String[] values;
    private Map<String, Integer> mapping;
    private String comment;
    private long recordNumber;

    @BeforeEach
    public void setUp() {
        values = new String[] {"value1", "value2", "value3"};
        mapping = new HashMap<>();
        mapping.put("col1", 0);
        mapping.put("col2", 1);
        mapping.put("col3", 2);
        comment = "comment";
        recordNumber = 1L;
        csvRecord = new CSVRecord(values, mapping, comment, recordNumber);
    }

    @Test
    public void testIteratorReturnsValuesIterator() {
        Iterator<String> iterator = csvRecord.iterator();
        assertNotNull(iterator);

        List<String> iterated = new ArrayList<>();
        while (iterator.hasNext()) {
            iterated.add(iterator.next());
        }
        assertEquals(Arrays.asList(values), iterated);
    }

    @Test
    public void testIteratorOnEmptyValues() throws NoSuchMethodException, InvocationTargetException, IllegalAccessException {
        // Use reflection to create a CSVRecord with empty values and null mapping
        String[] emptyValues = new String[0];
        Map<String, Integer> emptyMapping = Collections.emptyMap();
        CSVRecord emptyRecord = new CSVRecord(emptyValues, emptyMapping, null, 0L);

        Iterator<String> iterator = emptyRecord.iterator();
        assertNotNull(iterator);
        assertFalse(iterator.hasNext());

        // Also test toList private method returns empty list
        Method toListMethod = CSVRecord.class.getDeclaredMethod("toList");
        toListMethod.setAccessible(true);
        @SuppressWarnings("unchecked")
        List<String> list = (List<String>) toListMethod.invoke(emptyRecord);
        assertNotNull(list);
        assertTrue(list.isEmpty());
    }
}
